export const DROP_INDICATOR_CLASSES = [
  /* ── Drop indicator line (applied to <table>) ── */
  `[&_.react-aria-DropIndicator[data-drop-target]>td]:relative`,
  `[&_.react-aria-DropIndicator[data-drop-target]>td]:after:content-[""]`,
  `[&_.react-aria-DropIndicator[data-drop-target]>td]:after:absolute`,
  `[&_.react-aria-DropIndicator[data-drop-target]>td]:after:inset-x-0`,
  `[&_.react-aria-DropIndicator[data-drop-target]>td]:after:-top-px`,
  `[&_.react-aria-DropIndicator[data-drop-target]>td]:after:h-0.5`,
  `[&_.react-aria-DropIndicator[data-drop-target]>td]:after:bg-brand-solid`,
  /* ── Hide drop indicators inside parent/child groups ── */
  `[&_.react-aria-DropIndicator:has(+[data-child-row])]:hidden`,
  `[&_[data-child-row]:not([data-last-child])+.react-aria-DropIndicator]:hidden`,
  /* ── Hide drop indicator above the dragged row (no-op drop) ── */
  `[&_.react-aria-DropIndicator:has(+[data-dragging])]:hidden`,
].join(' ');
