import type { FC, ReactNode } from 'react';
import { Dropdown } from '@/components/atoms/Dropdown/base';
import { ButtonUtility } from '@/components/atoms/ButtonUtility';
import { WithDataId } from '@/types/withDataId';

type IconComponent = FC<{ className?: string }>;

const MAX_INLINE_ACTIONS = 2;

export interface TableAction {
  dataId: string;
  label: string;
  icon: IconComponent;
  onClick: () => void;
  isDisabled?: boolean;
  tooltip?: string;
}

export interface TableActionSeparator {
  type: 'separator';
}

export interface TableActionCustom {
  type: 'custom';
  render: () => ReactNode;
  dataId: string;
}

export type TableActionItem =
  | TableAction
  | TableActionSeparator
  | TableActionCustom;

export interface TableActionsProps extends Partial<WithDataId> {
  actions: TableActionItem[];
  /** Accessible label for the action group. Defaults to "Row actions". */
  'aria-label'?: string;
  maxInlineActions?: number;
}

function isCustom(item: TableActionItem): item is TableActionCustom {
  return 'type' in item && item.type === 'custom';
}

export function TableActions({
  actions,
  'data-id': dataId,
  'aria-label': ariaLabel = 'Row actions',
  maxInlineActions = MAX_INLINE_ACTIONS,
}: TableActionsProps) {
  const inlineActions = actions.slice(0, maxInlineActions);
  const overflowActions = actions.slice(maxInlineActions);

  const isSeparator = (
    action: TableActionItem,
  ): action is TableActionSeparator => 'type' in action;

  return (
    <div
      role="group"
      aria-label={ariaLabel}
      className="flex justify-end gap-1"
    >
      {inlineActions.map((action) => {
        if (isCustom(action)) {
          return action.render();
        }

        return !isSeparator(action) ? (
          <ButtonUtility
            key={action.dataId}
            data-id={action.dataId}
            icon={action.icon}
            tooltip={action.label}
            color="tertiary"
            onClick={action.onClick}
            isDisabled={action.isDisabled}
          />
        ) : null;
      })}
      {overflowActions.length > 0 && (
        <Dropdown.Root>
          <Dropdown.DotsButton
            data-id={`${dataId}-trigger`}
            horizontal
          />
          <Dropdown.Popover className="w-min">
            <Dropdown.Menu>
              {overflowActions.map((action, index) => {
                if (isSeparator(action)) {
                  return (
                    <Dropdown.Separator key={`${dataId}-separator-${index}`} />
                  );
                }

                if (isCustom(action)) {
                  return (
                    <Dropdown.Item
                      key={`${dataId}-custom-action-${index}`}
                      data-id={action.dataId}
                      unstyled
                    >
                      {action.render()};
                    </Dropdown.Item>
                  );
                }

                return (
                  <Dropdown.Item
                    key={action.dataId}
                    data-id={action.dataId}
                    icon={action.icon}
                    onClick={action.onClick}
                    isDisabled={action.isDisabled}
                    tooltip={action.tooltip}
                  >
                    {action.label}
                  </Dropdown.Item>
                );
              })}
            </Dropdown.Menu>
          </Dropdown.Popover>
        </Dropdown.Root>
      )}
    </div>
  );
}
