import { ArrowDown } from '@untitledui/icons/ArrowDown';
import { HelpCircle } from '@untitledui/icons/HelpCircle';
import { ChevronSelectorVertical } from '@untitledui/icons/ChevronSelectorVertical';

import { Tooltip } from '@/components/atoms/Tooltip';
import {
  Column as AriaColumn,
  Group as AriaGroup,
  useTableOptions,
} from 'react-aria-components';
import { cx } from '@/utils/cx';

import { TableHeadProps } from './_types';
import { WithDataId } from '@/types/withDataId';
import { TableHeadLabel } from './HeadLabel';
import { COL_SIZE_CLASS } from './_consts';

export function TableHead({
  className,
  tooltip,
  label,
  shouldHideLabel,
  children,
  size,
  'data-id': dataId,
  ...props
}: TableHeadProps & WithDataId) {
  const { selectionBehavior } = useTableOptions();
  return (
    <AriaColumn
      {...props}
      className={(state) =>
        cx(
          'relative p-0 outline-hidden focus-visible:z-1 focus-visible:ring-2 focus-visible:ring-focus-ring focus-visible:ring-offset-bg-primary focus-visible:ring-inset',
          selectionBehavior === 'toggle' && 'nth-2:pl-3',
          state.allowsSorting && 'cursor-pointer',
          typeof className === 'function' ? className(state) : className,
        )
      }
    >
      {(state) => (
        <AriaGroup
          className={cx(
            'flex items-center gap-1',
            size && COL_SIZE_CLASS[size],
          )}
        >
          <div className="flex items-center gap-1 overflow-hidden">
            {label && (
              <TableHeadLabel
                label={label}
                shouldHideLabel={shouldHideLabel}
                data-id={`${dataId}-label`}
              />
            )}
            {typeof children === 'function' ? children(state) : children}
          </div>

          {tooltip && (
            <Tooltip
              title={tooltip.title}
              description={tooltip.description}
              arrow={tooltip.arrow ?? false}
              placement="top"
              triggerProps={{
                'aria-label':
                  typeof tooltip.title === 'string' ? tooltip.title : 'Help',
                className:
                  'text-fg-quaternary transition duration-100 ease-linear hover:text-fg-quaternary_hover focus:text-fg-quaternary_hover',
              }}
              data-id={`${dataId}-tooltip`}
            >
              <HelpCircle size={16} />
            </Tooltip>
          )}

          {state.allowsSorting &&
            (state.sortDirection ? (
              <ArrowDown
                className={cx(
                  'size-3 stroke-[3px] text-fg-quaternary shrink-0',
                  state.sortDirection === 'ascending' && 'rotate-180',
                )}
              />
            ) : (
              <ChevronSelectorVertical
                size={12}
                strokeWidth={3}
                className="text-fg-quaternary shrink-0"
              />
            ))}
        </AriaGroup>
      )}
    </AriaColumn>
  );
}
