import { Checkbox } from '@/components/atoms/Checkbox';

import { isColumnSelected } from './_utils';

import type { TableRow, ColDef } from './_types';

export function ColumnCheckboxList<TData extends TableRow>({
  columns,
  allColumnDefs,
  columnsSelection,
  onColumnsSelectedChange,
  onColumnsSelectionChange,
  texts,
  dataId,
}: {
  columns: ColDef<TData>[];
  allColumnDefs: ColDef<TData>[];

  columnsSelection?: Record<string, boolean>;
  onColumnsSelectedChange?: (cols: Record<string, boolean>) => void;

  /** @deprecated Use onColumnsSelectedChange instead */
  onColumnsSelectionChange: (cols: ColDef<TData>[]) => void;

  texts: { columnsSelector: Record<string, string> };
  dataId: string | undefined;
}) {
  const { selectedAmount, unselectedAmount } = columns.reduce(
    (acc, c) => {
      const isSelected = isColumnSelected(c, columnsSelection);

      if (isSelected) {
        acc.selectedAmount += 1;
      } else {
        acc.unselectedAmount += 1;
      }

      return acc;
    },
    {
      selectedAmount: 0,
      unselectedAmount: 0,
    },
  );

  const isAllSelected = selectedAmount === columns.length;
  const isAllUnselected = unselectedAmount === columns.length;
  const isAllIndeterminate = !isAllSelected && !isAllUnselected;

  // Sort checked items to the top
  const sorted = [...columns].sort((a, b) => {
    const aSelected = !isColumnSelected(a, columnsSelection) ? 0 : 1;
    const bSelected = !isColumnSelected(b, columnsSelection) ? 0 : 1;

    return bSelected - aSelected;
  });

  return (
    <div className="overflow-y-auto max-h-120 pb-2">
      <div className="px-3 py-1.5">
        <Checkbox
          isSelected={isAllSelected}
          isIndeterminate={isAllIndeterminate}
          label={texts.columnsSelector.selectAllCheckboxLabel}
          onChange={() => {
            const newSelected = !isAllSelected;
            const columnIds = new Set(columns.map((c) => c.id));
            const cols = allColumnDefs.map((c) =>
              c.alwaysVisible || !columnIds.has(c.id)
                ? c
                : { ...c, isSelected: newSelected },
            );
            onColumnsSelectionChange(cols);

            onColumnsSelectedChange?.(
              allColumnDefs.reduce(
                (acc, c) => ({
                  ...acc,
                  [String(c.id)]: c.alwaysVisible || newSelected,
                }),
                {} as Record<string, boolean>,
              ),
            );
          }}
          data-id={`${dataId}-selectAll`}
        />
      </div>

      {sorted.map((column) => {
        const isVisible = isColumnSelected(column, columnsSelection);

        return (
          <div
            key={column.id}
            className="px-3 py-1.5"
          >
            <Checkbox
              isSelected={isVisible}
              aria-label={`${texts.columnsSelector.toggleCheckboxAriaLabel} ${column.label}`}
              label={column.label}
              onChange={() => {
                const cols = allColumnDefs.map((c) => {
                  if (c.id === column.id) {
                    return {
                      ...c,
                      isSelected:
                        column.isSelected === undefined ? false : !isVisible,
                    };
                  }
                  return c;
                });

                onColumnsSelectionChange(cols);

                const selectedCols = allColumnDefs.reduce(
                  (acc, c) => {
                    const isSelected = isColumnSelected(c, columnsSelection);

                    return {
                      ...acc,
                      [String(c.id)]:
                        c.id === column.id ? !isSelected : isSelected,
                    };
                  },
                  {} as Record<string, boolean>,
                );

                onColumnsSelectedChange?.(selectedCols);
              }}
              data-id={`${dataId}-checkbox-${column.id}`}
            />
          </div>
        );
      })}
    </div>
  );
}
