import { useMemo } from 'react';
import { Select } from '@/components/atoms/Select/BaseSelect';
import { cx } from '@/utils/cx';

import type { TablePaginationPageLimitProps } from './_types';

function getPageSizeOptions(sizes: number[]): { label: string; id: string }[] {
  return sizes.map((size) => ({
    label: String(size),
    id: String(size),
  }));
}

const DEFAULT_LIMITS = [20, 50, 100];

type Props = TablePaginationPageLimitProps & {
  label: string;
  className?: string;
};

export function PageSizeSelect({
  paginationPageSize,
  paginationPageSizeSelector,
  onPaginationChanged,
  onPageLimitChange,
  label,
  className,
}: Props) {
  const limits = useMemo(
    () =>
      Array.isArray(paginationPageSizeSelector)
        ? getPageSizeOptions(paginationPageSizeSelector)
        : getPageSizeOptions(DEFAULT_LIMITS),
    [paginationPageSizeSelector],
  );

  return (
    <div className={cx('flex items-center gap-2', className)}>
      <p className="font-semibold text-secondary text-sm">{label}:</p>
      <Select
        className="w-20"
        defaultSelectedKey={String(paginationPageSize)}
        aria-labelledby="select-items-per-page"
        items={limits}
        onSelectionChange={(value) => {
          const limit = Number(value);

          onPaginationChanged?.({ newPageSize: limit });

          onPageLimitChange?.(limit);
        }}
      >
        {(item) => <Select.Item id={item.id}>{item.label}</Select.Item>}
      </Select>
    </div>
  );
}
