import { ConditionalTooltip } from '@/components/atoms/Tooltip';
import { useTruncation } from '@/hooks/use-truncation';
import { WithDataId } from '@/types/withDataId';
import { cx } from '@/utils/cx';

import { TableHeadLabelProps } from './_types';

export function TableHeadLabel({
  label,
  shouldHideLabel,
}: TableHeadLabelProps & WithDataId) {
  const { ref, isTruncated } = useTruncation<HTMLSpanElement>('x');

  return (
    <ConditionalTooltip
      text={label}
      isTruncated={isTruncated}
    >
      <span
        ref={ref}
        className={cx(
          'inline-block',
          shouldHideLabel
            ? 'sr-only'
            : 'text-xs font-semibold whitespace-nowrap text-quaternary text-left text-ellipsis overflow-hidden',
        )}
      >
        {label}
      </span>
    </ConditionalTooltip>
  );
}
