import { Button } from '@/components/atoms/Button/BaseButton';
import { Pagination } from '@/vendor/untitled-ui/application/pagination/pagination-base';
import { ArrowLeft } from '@untitledui/icons/ArrowLeft';
import { ArrowRight } from '@untitledui/icons/ArrowRight';
import { useBreakpoint } from '@/hooks/use-breakpoint';
import { cx } from '@/utils/cx';

import { DEFAULT_TEXTS } from './_consts';
import type { TablePaginationProps } from './_types';
import { PageSizeSelect } from './PageSizeSelect';

export function TablePagination({
  paginationCurrentPage,
  paginationTotalItems,
  paginationPageSize,
  paginationPageSizeSelector,
  paginationText,
  onPaginationChanged,
  onPageLimitChange,
  onPageNumberChange,
  t,
}: TablePaginationProps) {
  const texts = { ...DEFAULT_TEXTS.pagination, ...t?.pagination };
  const isDesktop = useBreakpoint('md');

  return (
    <div className="flex w-full items-center justify-between gap-3 border-t border-secondary px-4 py-3 md:px-6 md:pt-3 md:pb-4">
      {paginationText ? (
        <p className="flex flex-1 font-semibold text-secondary text-sm">
          {paginationText}
        </p>
      ) : paginationPageSizeSelector ? (
        <PageSizeSelect
          paginationPageSize={paginationPageSize}
          paginationPageSizeSelector={paginationPageSizeSelector}
          onPaginationChanged={onPaginationChanged}
          onPageLimitChange={onPageLimitChange}
          label={texts.labelItemsPerPage}
        />
      ) : null}
      <Pagination.Root
        page={paginationCurrentPage}
        total={Math.ceil(paginationTotalItems / paginationPageSize)}
        onPageChange={(page) => {
          onPaginationChanged?.({ newPage: page });

          onPageNumberChange?.(page);
        }}
        className="flex items-center justify-between gap-3"
      >
        <div className="flex flex-1 justify-start">
          <Pagination.PrevTrigger asChild>
            <Button
              iconLeading={ArrowLeft}
              color="secondary"
              size="sm"
            >
              {isDesktop ? texts.labelPrevious : null}
            </Button>
          </Pagination.PrevTrigger>
        </div>

        <Pagination.Context>
          {({ pages }) => (
            <div className="hidden items-center justify-center gap-0.5 md:flex">
              {pages.map((page, index) =>
                page.type === 'page' ? (
                  <Pagination.Item
                    key={index}
                    asChild
                    {...page}
                  >
                    <Button
                      color="tertiary"
                      size="sm"
                      className={cx(
                        'font-medium',
                        page.isCurrent && 'bg-primary_hover text-secondary',
                      )}
                    >
                      {page.value}
                    </Button>
                  </Pagination.Item>
                ) : (
                  <Pagination.Ellipsis
                    key={index}
                    className="flex size-10 shrink-0 items-center justify-center text-tertiary"
                  >
                    &#8230;
                  </Pagination.Ellipsis>
                ),
              )}
            </div>
          )}
        </Pagination.Context>

        <div className="flex flex-1 justify-end">
          <Pagination.NextTrigger asChild>
            <Button
              iconTrailing={ArrowRight}
              color="secondary"
              size="sm"
            >
              {isDesktop ? texts.labelNext : null}
            </Button>
          </Pagination.NextTrigger>
        </div>
      </Pagination.Root>
      {paginationText && paginationPageSizeSelector ? (
        <PageSizeSelect
          paginationPageSize={paginationPageSize}
          paginationPageSizeSelector={paginationPageSizeSelector}
          onPaginationChanged={onPaginationChanged}
          onPageLimitChange={onPageLimitChange}
          label={texts.labelItemsPerPage}
          className="flex-1 justify-end"
        />
      ) : null}
    </div>
  );
}
