import { useCallback, useEffect, useRef, useState } from 'react';
import { ColDef, TableRow } from '../_types';

export function useStickyColumns<TData extends TableRow>(
  visibleColumns: ColDef<TData>[],
  { enabled }: { enabled: boolean },
) {
  // Track the wrapper element via state (driven by a callback ref) instead of
  // a plain object ref. Consumers can render the table conditionally — e.g.
  // an empty state on first paint that's later swapped for the table — so the
  // ref can attach *after* the first effect runs. Putting the element in
  // state adds it to the effect's deps, ensuring the effect re-runs as soon
  // as the wrapper mounts.
  const [wrapper, setWrapper] = useState<HTMLDivElement | null>(null);
  const wrapperRef = useCallback(
    (node: HTMLDivElement | null) => {
      // Skip the state update when disabled so consumers (e.g. tables with no
      // pinned columns) don't pay for an extra render on mount.
      if (!enabled) {
        return;
      }

      setWrapper(node);
    },
    [enabled],
  );

  const styleElRef = useRef<HTMLStyleElement | null>(null);
  const scopeIdRef = useRef('');

  useEffect(() => {
    if (!wrapper || !enabled) return;

    const table = wrapper.querySelector('table');
    if (!table) return;

    const scrollContainer = table.parentElement;
    if (!scrollContainer) return;

    const pinnedLeftIndexes: number[] = [];
    const pinnedRightIndexes: number[] = [];

    visibleColumns.forEach((col, i) => {
      if (col.pinned === 'left') pinnedLeftIndexes.push(i);
      if (col.pinned === 'right') pinnedRightIndexes.push(i);
    });

    if (pinnedLeftIndexes.length === 0 && pinnedRightIndexes.length === 0)
      return;

    // Assign a unique scope to this table so CSS rules don't leak across instances
    if (!scopeIdRef.current) {
      scopeIdRef.current = `sticky-${Math.random().toString(36).slice(2, 8)}`;
    }
    const scopeId = scopeIdRef.current;
    table.setAttribute('data-sticky', scopeId);

    const buildStyles = () => {
      // --- Read: measure cell widths from the header row ---
      const headerCells =
        table.querySelectorAll<HTMLTableCellElement>('thead th, thead td');

      // react-aria-components may auto-inject leading cells (selection
      // checkbox when selectionMode is set, drag handles, etc.) that don't
      // correspond to entries in `visibleColumns`. They appear before the
      // user's columns in the DOM, so every visibleColumns index needs to be
      // shifted by this amount when targeting nth-child / measuring widths.
      const domOffset = Math.max(0, headerCells.length - visibleColumns.length);

      // Treat auto-injected leading cells as implicit pinned-left so they
      // stay visible alongside user pinned-left columns when scrolling.
      // Their absence from visibleColumns means we'd otherwise leave them
      // floating without a stick rule.
      const autoLeftIndexes: number[] =
        pinnedLeftIndexes.length > 0
          ? Array.from({ length: domOffset }, (_, i) => i)
          : [];

      const leftDomIndexes = [
        ...autoLeftIndexes,
        ...pinnedLeftIndexes.map((i) => i + domOffset),
      ];
      const rightDomIndexes = pinnedRightIndexes.map((i) => i + domOffset);

      const leftWidths = leftDomIndexes.map(
        (i) => headerCells[i]?.offsetWidth ?? 0,
      );
      const rightWidths = rightDomIndexes.map(
        (i) => headerCells[i]?.offsetWidth ?? 0,
      );

      // Cumulative left offsets
      const leftOffsets: number[] = [];
      let accLeft = 0;
      for (const w of leftWidths) {
        leftOffsets.push(accLeft);
        accLeft += w;
      }

      // Cumulative right offsets (accumulated from the end)
      const rightOffsets: number[] = [];
      let accRight = 0;
      for (let i = rightWidths.length - 1; i >= 0; i--) {
        rightOffsets[i] = accRight;
        accRight += rightWidths[i];
      }

      // --- Write: build CSS rules that apply to all rows via selectors ---
      const scope = `table[data-sticky="${scopeId}"]`;
      const col = (domIndex: number) =>
        `${scope} tr > :nth-child(${domIndex + 1})`;

      const rules: string[] = [];

      // Rows need an opaque background so sticky cells can inherit it
      rules.push(
        `${scope} thead tr { background-color: var(--color-bg-secondary); }`,
      );
      rules.push(
        `${scope} tbody tr { background-color: var(--color-bg-primary); }`,
      );

      for (let i = 0; i < leftDomIndexes.length; i++) {
        rules.push(
          `${col(leftDomIndexes[i])} { position: sticky; left: ${leftOffsets[i]}px; z-index: 20; background-color: inherit; }`,
        );
      }

      for (let i = 0; i < rightDomIndexes.length; i++) {
        rules.push(
          `${col(rightDomIndexes[i])} { position: sticky; right: ${rightOffsets[i]}px; z-index: 20; background-color: inherit; }`,
        );
      }

      // Shadow on last left-pinned column (visible only when scrolled from start)
      if (leftDomIndexes.length > 0) {
        const lastLeft = leftDomIndexes[leftDomIndexes.length - 1];
        rules.push(
          `${scope}[data-scrolled-start] tr > :nth-child(${lastLeft + 1})::before { content: ''; position: absolute; top: 0; bottom: 0; right: -4px; width: 0.25rem; background: linear-gradient(to right, rgb(0 0 0 / 0.06), transparent); pointer-events: none; }`,
        );
      }

      // Shadow on first right-pinned column (visible only when not scrolled to end)
      if (rightDomIndexes.length > 0) {
        const firstRight = rightDomIndexes[0];
        rules.push(
          `${scope}[data-scrolled-end] tr > :nth-child(${firstRight + 1})::before { content: ''; position: absolute; top: 0; bottom: 0; left: -4px; width: 0.25rem; background: linear-gradient(to left, rgb(0 0 0 / 0.06), transparent); pointer-events: none; }`,
        );
      }

      if (!styleElRef.current) {
        const style = document.createElement('style');
        wrapper.appendChild(style);
        styleElRef.current = style;
      }
      styleElRef.current.textContent = rules.join('\n');
    };

    const updateShadows = () => {
      const { scrollLeft, scrollWidth, clientWidth } = scrollContainer;
      table.toggleAttribute('data-scrolled-start', scrollLeft > 0);
      table.toggleAttribute(
        'data-scrolled-end',
        scrollLeft + clientWidth < scrollWidth - 1,
      );
    };

    buildStyles();
    updateShadows();

    scrollContainer.addEventListener('scroll', updateShadows, {
      passive: true,
    });

    // Recalculate widths on resize — no MutationObserver needed since
    // CSS nth-child rules automatically apply to new/removed rows
    let rafId = 0;
    const resizeObserver = new ResizeObserver(() => {
      cancelAnimationFrame(rafId);
      rafId = requestAnimationFrame(buildStyles);
    });
    resizeObserver.observe(scrollContainer);

    return () => {
      cancelAnimationFrame(rafId);
      resizeObserver.disconnect();
      scrollContainer.removeEventListener('scroll', updateShadows);
      styleElRef.current?.remove();
      styleElRef.current = null;
      table.removeAttribute('data-sticky');
      table.removeAttribute('data-scrolled-start');
      table.removeAttribute('data-scrolled-end');
    };
  }, [wrapper, visibleColumns, enabled]);

  return wrapperRef;
}
